syntax = "proto3";

package api.v1;

// Previously: string email = 2; — this change reassigns the existing field
// to a new tag, breaking every already-deployed client.
message User {
  string id = 1;
  string email = 7;
}

syntax = "proto3";

package api.v1;

// Adds a new optional field with a fresh number; existing tags untouched.
message User {
  string id = 1;
  string email = 2;
  optional string display_name = 3;
}
